// Generate all subgraphs of G
FUNCTION GenerateSubgraphs(G):
 n = |V(G)|
 subgraphs = []
 vertices = List(V(G))

 // For each subset of vertices (excluding empty)
 FOR subsetMask from 1 to (2^n) - 1:
 // Get vertex subset
 Vsub = []
 FOR i from 0 to n-1:
 IF (subsetMask >> i) & 1 == 1:
 Vsub.add(vertices[i])

 // Create induced subgraph on Vsub
 Esub = []
 FOR each edge (u,v) in E(G):
 IF u in Vsub AND v in Vsub:
 Esub.add((u,v))

 subgraphs.add(Graph(Vsub, Esub))

 RETURN subgraphs

